import{_ as o,o as r,c as a,ai as l}from"./chunks/framework.DMjte4z8.js";const d=JSON.parse('{"title":"触发器事件类型详解","description":"","frontmatter":{"title":"触发器事件类型详解","category":"triggers","updated":"2026-05-07T00:00:00.000Z","model":"minimax/MiniMax-M2.7-highspeed","quality_score":0.72,"discovered_via":"manual","sources":["https://www.hiveworkshop.com/threads/basics-of-triggers.32113/","https://world-editor-tutorials.thehelper.net/cat_usersubmit.php?view=19780","https://thelazzoro.github.io/BetterTriggersGuide"]},"headers":[],"relativePath":"triggers/触发器事件类型详解.md","filePath":"triggers/触发器事件类型详解.md","lastUpdated":1779351155000}'),e={name:"triggers/触发器事件类型详解.md"};function i(n,t,s,u,q,g){return r(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="触发器事件类型详解" tabindex="-1">触发器事件类型详解 <a class="header-anchor" href="#触发器事件类型详解" aria-label="Permalink to “触发器事件类型详解”">​</a></h1><h2 id="触发器事件类型概述" tabindex="-1">触发器事件类型概述 <a class="header-anchor" href="#触发器事件类型概述" aria-label="Permalink to “触发器事件类型概述”">​</a></h2><p>本节我们将学习什么是&quot;触发器&quot;（Trigger），以及触发器的基本结构。触发器是魔兽争霸3地图的灵魂——它能让你的地图&quot;活&quot;起来，比如&quot;当玩家点击按钮时，给英雄加100金币&quot;这样的逻辑，都靠触发器实现。</p><h3 id="触发器基本结构-事件-条件-动作" tabindex="-1">触发器基本结构（事件-条件-动作） <a class="header-anchor" href="#触发器基本结构-事件-条件-动作" aria-label="Permalink to “触发器基本结构（事件-条件-动作）”">​</a></h3><p>触发器就像一个&quot;如果...那么...&quot;的机器，它由三部分组成：<strong>事件（Event）</strong>、<strong>条件（Condition）</strong>、<strong>动作（Action）</strong>[^1]。</p><blockquote><p><strong>💡 新手提示</strong>：可以把触发器想象成一道&quot;如果...就...&quot;的数学题：</p><ul><li><strong>事件</strong>：如果发生什么事...</li><li><strong>条件</strong>：并且满足什么条件...</li><li><strong>动作</strong>：那么就执行什么操作</li></ul></blockquote><h3 id="事件在触发器中的作用" tabindex="-1">事件在触发器中的作用 <a class="header-anchor" href="#事件在触发器中的作用" aria-label="Permalink to “事件在触发器中的作用”">​</a></h3><p><strong>事件</strong>是触发器的&quot;开关&quot;——没有事件，触发器永远不会运行。你可以理解为：事件就是&quot;告诉触发器&#39;什么时候开始工作&#39;&quot;。常见的事件包括[^1][^2]：</p><table tabindex="0"><thead><tr><th>事件类型</th><th>含义</th></tr></thead><tbody><tr><td>单位死亡</td><td>当某个单位死亡时</td></tr><tr><td>单位进入区域</td><td>当单位走进某个区域时</td></tr><tr><td>玩家聊天</td><td>当玩家输入聊天信息时</td></tr><tr><td>定时器到期</td><td>每隔一段时间</td></tr></tbody></table><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>完成以上内容后，你应该理解了：</p><ul><li>触发器由<strong>事件-条件-动作</strong>三部分组成</li><li><strong>事件</strong>决定了触发器&quot;何时启动&quot;</li><li>不同的<strong>事件类型</strong>对应不同的游戏情况</li></ul><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手会混淆&quot;条件&quot;和&quot;动作&quot;。记住：<strong>条件</strong>是&quot;检查一下&quot;，<strong>动作</strong>是&quot;真的去做&quot;。条件可以没有，但事件必须有，否则触发器永远不会运行！</p></blockquote><h2 id="地图初始化与游戏开始事件" tabindex="-1">地图初始化与游戏开始事件 <a class="header-anchor" href="#地图初始化与游戏开始事件" aria-label="Permalink to “地图初始化与游戏开始事件”">​</a></h2><p>在本节中，你将学习如何创建<strong>地图初始化事件</strong>和<strong>游戏开始事件</strong>——这是几乎所有RPG地图最先执行的两个核心事件。学会它们之后，你就能在玩家进入游戏的第一时间设置变量、创建单位、显示欢迎信息等功能[^1]。</p><h3 id="地图加载事件" tabindex="-1">地图加载事件 <a class="header-anchor" href="#地图加载事件" aria-label="Permalink to “地图加载事件”">​</a></h3><p>地图加载事件（又叫&quot;地图初始化&quot;）会在地图完全加载时自动触发，不需要玩家做任何操作。这是最适合做<strong>准备工作</strong>的事件，比如初始化变量（存放数据的容器）、预加载资源等。</p><h4 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to “操作步骤”">​</a></h4><ol><li><strong>打开触发器编辑器</strong> — 在World Editor顶部菜单栏点击&quot;触发器&quot;按钮（或者按快捷键F4）[^1]</li><li><strong>新建一个触发器</strong> — 在左侧面板空白处右键，选择&quot;新建触发器&quot;，将它改名为&quot;初始化设置&quot;</li><li><strong>添加事件</strong> — 点击触发器中的&quot;事件&quot;区域，在弹出的列表中找到&quot;地图初始化&quot;并点击选择</li><li><strong>添加动作</strong> — 点击&quot;动作&quot;区域，从左侧分类中找到&quot;游戏-显示教程提示&quot;（这只是测试用，实际项目中你会添加更多初始化动作）</li></ol><blockquote><p><strong>💡 新手提示</strong>：地图初始化事件会在<strong>任何玩家</strong>进入地图之前就触发，所以如果你想设置只有某个玩家能看到的UI，需要使用&quot;游戏开始事件&quot;而不是这里的事件。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常把初始化代码写在错误的位置（比如写在&quot;单位死亡&quot;事件里），导致游戏开始时变量还没准备好。记住：所有<strong>准备工作</strong>（设置初始变量、创建起始单位等）都应该放在&quot;地图初始化&quot;或&quot;游戏开始&quot;事件下。</p></blockquote><h3 id="游戏开始事件的使用场景" tabindex="-1">游戏开始事件的使用场景 <a class="header-anchor" href="#游戏开始事件的使用场景" aria-label="Permalink to “游戏开始事件的使用场景”">​</a></h3><p>&quot;游戏开始事件&quot;与&quot;地图初始化&quot;非常相似，但有一个关键区别：它会在<strong>所有玩家都进入地图后</strong>才触发。这对于需要等待所有玩家准备就绪的场景特别有用[^1]。</p><h4 id="适合使用游戏开始事件的场景" tabindex="-1">适合使用游戏开始事件的场景 <a class="header-anchor" href="#适合使用游戏开始事件的场景" aria-label="Permalink to “适合使用游戏开始事件的场景”">​</a></h4><ul><li>显示开场动画或过场文字</li><li>为每个玩家创建专属单位（如主角）</li><li>分配玩家的起始装备或金币</li><li>启动计时器或回合系统</li></ul><h4 id="操作步骤-1" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-1" aria-label="Permalink to “操作步骤”">​</a></h4><ol><li>在触发器编辑器中新建一个触发器，命名为&quot;游戏开始设置&quot;</li><li>在事件区域点击&quot;新事件&quot;按钮</li><li>在搜索框中输入&quot;游戏开始&quot;，从结果中选择&quot;游戏 - 游戏开始时&quot;</li><li>现在你可以添加具体的动作了，比如&quot;游戏 - 显示教程提示&quot;设置为&quot;欢迎来到口袋妖怪RPG！&quot;</li></ol><blockquote><p><strong>💡 新手提示</strong>：如果你不确定该用哪个事件，记住这个简单规则——需要所有玩家都就位才能执行的功能，用&quot;游戏开始&quot;；只需要地图加载好就能执行的准备操作，用&quot;地图初始化&quot;。</p></blockquote><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你已经掌握了：</p><ul><li>如何创建<strong>地图初始化事件</strong>并添加动作</li><li>如何创建<strong>游戏开始事件</strong>并设置玩家专属内容</li><li>两个事件的区别以及何时该用哪一个</li></ul><p>这两个事件是所有RPG地图的&quot;根基&quot;，建议你在制作任何地图时都先创建这两个触发器，把初始化代码整理好放在里面。</p><h2 id="玩家相关事件" tabindex="-1">玩家相关事件 <a class="header-anchor" href="#玩家相关事件" aria-label="Permalink to “玩家相关事件”">​</a></h2><p>在本节中，你将学习如何监听玩家的进出游戏状态以及聊天消息。掌握这些事件后，你就可以制作登录欢迎系统、聊天指令功能，甚至简单的文字RPG指令系统。</p><h3 id="操作步骤-2" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-2" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>打开触发器编辑器</strong> — 在World Editor（世界编辑器）界面，按 <code>F4</code> 键打开触发器编辑器窗口[^1]。如果没有触发器，可右键点击左侧列表，选择&quot;新建触发器&quot;创建。</p></li><li><p><strong>创建玩家进入事件</strong> — 展开&quot;事件&quot;分类，选择&quot;单位 - A unit enters playable area&quot;（单位进入可玩区域）。这个事件会在任意玩家的单位进入地图时触发，非常适合用来检测玩家加入游戏[^1]。</p></li><li><p><strong>创建玩家离开事件</strong> — 在事件列表中选择&quot;玩家 - Player leaves game&quot;（玩家离开游戏）。设置你想监听的具体玩家编号（0-23，对应红、绿、蓝等颜色）。</p></li><li><p><strong>创建聊天事件</strong> — 选择&quot;玩家 - Player Chat Message&quot;（玩家聊天信息）。在这里你可以设置：</p><ul><li>聊天前缀（如 &quot;/&quot; 或 &quot;!&quot;）</li><li>是否仅检测不含前缀的普通聊天</li></ul></li></ol><blockquote><p><strong>💡 新手提示</strong>：在设置玩家聊天事件时，&quot;Triggering Player&quot;（触发玩家）是一个非常重要的变量，它能帮你判断是谁发送了这条命令。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常把&quot;单位进入可玩区域&quot;和&quot;玩家离开游戏&quot;搞混。前者需要单位对象，后者只需要玩家编号。如果你想做登录欢迎界面，应该用玩家离开/进入游戏事件。</p></blockquote><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该已经掌握了三种最常用的玩家相关事件：</p><ul><li>单位进入可玩区域（适合检测玩家进入）</li><li>玩家离开游戏（适合做离开提示）</li><li>玩家聊天信息（适合做指令系统）</li></ul><p>你可以尝试组合这些事件，比如当玩家聊天输入 &quot;/help&quot; 时显示帮助信息，这正是很多RPG游戏指令系统的基础[^1]。</p><h2 id="单位事件详解" tabindex="-1">单位事件详解 <a class="header-anchor" href="#单位事件详解" aria-label="Permalink to “单位事件详解”">​</a></h2><p>本节将详细介绍 Warcraft III 触发器中最常用的<strong>单位事件</strong>类型。学完本节后，你将能够创建&quot;当某个单位出生时触发&quot;、&quot;当单位受伤时触发&quot;等功能，让你的地图具有更强的交互性。</p><h3 id="单位出生与死亡事件" tabindex="-1">单位出生与死亡事件 <a class="header-anchor" href="#单位出生与死亡事件" aria-label="Permalink to “单位出生与死亡事件”">​</a></h3><p>单位出生与死亡事件是 RPG 地图中最基础的事件类型，常用于任务系统、奖励发放或怪物刷新。</p><h4 id="操作步骤-3" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-3" aria-label="Permalink to “操作步骤”">​</a></h4><ol><li><strong>打开触发编辑器</strong> — 在 World Editor 界面顶部菜单栏点击「触发器」按钮（或者按 F4 快捷键）[^1]</li><li><strong>创建新触发器</strong> — 右键左侧触发器列表，选择「新建触发器」，命名为&quot;单位死亡检测&quot;</li><li><strong>添加事件</strong> — 点击触发器右上角的「新增事件」按钮，在弹出窗口中选择「单位 - 单位死亡」[^2]</li><li><strong>设置条件（可选）</strong> — 添加「单位 - 单位属于敌对单位」等条件来过滤不需要的死亡事件</li><li><strong>添加动作</strong> — 添加「游戏 - 显示教程提示」等动作来测试效果</li></ol><blockquote><p><strong>💡 新手提示</strong>：单位死亡事件只能检测&quot;真正死亡&quot;的情况，如果单位被放逐（Banish）或变形，不会触发此事件。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常把「单位复活」事件和「单位出生」事件混淆。「单位出生」只在完全新建单位时触发，复活单位请使用「单位 - 单位进入区域」事件。</p></blockquote><h3 id="单位被攻击与受伤事件" tabindex="-1">单位被攻击与受伤事件 <a class="header-anchor" href="#单位被攻击与受伤事件" aria-label="Permalink to “单位被攻击与受伤事件”">​</a></h3><p>这类事件让你可以监听单位的战斗状态，用于制作反击系统、伤害显示或闪避判定。</p><h4 id="操作步骤-4" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-4" aria-label="Permalink to “操作步骤”">​</a></h4><ol><li><strong>新建触发器</strong> — 命名为&quot;受伤检测&quot;</li><li><strong>添加事件</strong> — 选择「单位 - 单位受到攻击」或「单位 - 单位受到伤害」[^2]</li><li><strong>获取受伤单位</strong> — 从事件函数中选择「受到攻击的单位」或「受到伤害的单位」</li><li><strong>创建变量</strong> — 新建「受伤单位」变量，类型为「单位」，用于存储事件触发的单位</li><li><strong>添加动作示例</strong> — 比如播放受伤音效、显示伤害数字或触发反击逻辑</li></ol><blockquote><p><strong>💡 新手提示</strong>：「受到攻击」和「受到伤害」的区别在于：攻击是攻击动作开始时触发，伤害是实际扣血时触发。如果单位有护盾或闪避技能，两者触发时机可能不同。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：不要在受伤事件中无限循环添加buff，这会导致游戏卡顿。每次受伤最多添加一次增益效果，建议配合「布尔变量」来控制。</p></blockquote><h3 id="单位获得-失去增益事件" tabindex="-1">单位获得/失去增益事件 <a class="header-anchor" href="#单位获得-失去增益事件" aria-label="Permalink to “单位获得/失去增益事件”">​</a></h3><p>增益（Buff）事件用于监听魔法效果的施加与移除，是技能系统、自动治疗等机制的基础[^3]。</p><h4 id="操作步骤-5" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-5" aria-label="Permalink to “操作步骤”">​</a></h4><ol><li><strong>新建触发器</strong> — 命名为&quot;Buff监听&quot;</li><li><strong>添加事件</strong> — 选择「单位 - 单位获得增益」或「单位 - 单位失去增益」</li><li><strong>获取增益类型</strong> — 从事件函数中选择「被施放的技能」来判断是什么buff</li><li><strong>条件设置</strong> — 添加条件判断，如「技能等于 圣光术」</li><li><strong>添加对应动作</strong> — 例如获得治疗buff时添加回血动作，失去buff时移除相关效果</li></ol><blockquote><p><strong>💡 新手提示</strong>：学会善用「拥有技能/拥有buff」条件检测。你可以用这个制作&quot;中毒时移动速度降低&quot;或&quot;获得隐身buff后隐藏单位&quot;等功能。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手容易忽略「失去增益」事件的处理。如果没有正确移除对应的视觉效果或逻辑状态，单位可能会出现&quot;假死&quot;或&quot;永久隐身&quot;的bug。</p></blockquote><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>完成以上三个单位事件类型的学习后，你应该掌握了：</p><ul><li>如何创建检测单位死亡并触发相应动作的触发器</li><li>如何获取受伤/被攻击的单位信息并进行逻辑处理</li><li>如何监听单位获得或失去特定buff并做出响应</li></ul><p>这些基础事件组合使用，可以构建出大多数 RPG 地图的核心战斗系统。建议下一步尝试制作一个&quot;怪物死亡后掉落金币&quot;的简单功能来巩固所学知识。</p><h2 id="时间与游戏进程事件" tabindex="-1">时间与游戏进程事件 <a class="header-anchor" href="#时间与游戏进程事件" aria-label="Permalink to “时间与游戏进程事件”">​</a></h2><p>本节将教你两种最常用的自动触发事件：<strong>周期性时间事件</strong>（每隔一段时间自动执行）和<strong>游戏时间事件</strong>（当游戏时间达到某个值时执行）。学完本节，你将能够创建&quot;每10秒生成一个怪物&quot;或&quot;游戏进行30分钟后显示胜利提示&quot;这样的功能。</p><h3 id="周期性时间事件" tabindex="-1">周期性时间事件 <a class="header-anchor" href="#周期性时间事件" aria-label="Permalink to “周期性时间事件”">​</a></h3><ol><li><p><strong>打开触发编辑器</strong> — 在顶部菜单栏点击&quot;触发器&quot;按钮，打开触发编辑器窗口[^1]</p></li><li><p><strong>选中或新建触发器</strong> — 在左侧触发器列表中，点击选择你要编辑的触发器（或者右键新建一个）</p></li><li><p><strong>添加事件</strong> — 在触发器编辑器中，点击&quot;事件&quot;区域，然后点击右侧的&quot;新建事件&quot;按钮</p></li><li><p><strong>选择时间事件类型</strong> — 在事件分类中找到&quot;时间&quot;类别，选择&quot;周期性事件&quot;下的&quot;每N秒后&quot;选项[^2]</p></li><li><p><strong>设置间隔时间</strong> — 在弹出的对话框中输入数字。例如输入&quot;10&quot;表示每隔10秒触发一次；输入&quot;0.5&quot;表示每0.5秒（每半秒）触发一次</p></li><li><p><strong>完成添加</strong> — 点击&quot;确定&quot;，事件就添加成功了</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：周期性事件的间隔时间可以是小数！如果想每2.5秒触发一次，直接输入&quot;2.5&quot;即可。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手容易把间隔时间设为&quot;0&quot;，这会导致触发器每秒执行极多次，可能导致游戏严重卡顿甚至崩溃。最小建议设置为&quot;0.1&quot;以上。</p></blockquote><h3 id="游戏时间与回合事件" tabindex="-1">游戏时间与回合事件 <a class="header-anchor" href="#游戏时间与回合事件" aria-label="Permalink to “游戏时间与回合事件”">​</a></h3><ol><li><p><strong>继续在事件区域操作</strong> — 在同一个触发器中（或新建另一个触发器），再次点击&quot;事件&quot;区域</p></li><li><p><strong>新建事件</strong> — 点击&quot;新建事件&quot;按钮</p></li><li><p><strong>选择游戏时间事件</strong> — 在&quot;时间&quot;分类下，选择&quot; elapsed game time equal to&quot;（已流逝游戏时间等于）选项[^1]</p></li><li><p><strong>设置触发时间点</strong> — 输入触发时刻（以秒为单位）。例如输入&quot;180&quot;表示游戏时间达到3分钟（180秒）时触发</p></li><li><p><strong>添加对应动作</strong> — 设置当游戏到达该时间时要执行的操作，比如&quot;显示胜利消息&quot;或&quot;触发结局剧情&quot;</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：游戏时间事件只会触发<strong>一次</strong>——当时间刚到达你设定的值时执行。如果你想让某个功能&quot;每分钟&quot;重复，应该用周期性事件而非游戏时间事件。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：混淆&quot;游戏时间&quot;和&quot;真实时间&quot;。Warcraft III的&quot;游戏时间&quot;是从游戏开始算起的内部计时器，不受暂停影响。暂停游戏时游戏时间不会前进。</p></blockquote><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该掌握了：</p><ul><li>如何添加<strong>周期性事件</strong>（每隔X秒自动执行）</li><li>如何添加<strong>游戏时间事件</strong>（当游戏进行到X秒时执行一次）</li><li>周期性事件适合循环任务（如刷怪、恢复生命）</li><li>游戏时间事件适合一次性剧情或阶段切换（如BOSS战、结局）</li></ul><p>你可以尝试创建一个&quot;每15秒在地图中央生成一个野生怪物&quot;的触发器，这是RPG地图中非常常见的机制！</p><h2 id="其他常用事件类型" tabindex="-1">其他常用事件类型 <a class="header-anchor" href="#其他常用事件类型" aria-label="Permalink to “其他常用事件类型”">​</a></h2><p>本节将介绍两组实用的事件类型：<strong>可破坏物与物品事件</strong>和<strong>对话框事件</strong>。学完后，你能让玩家拾取物品时获得奖励，或让玩家点击按钮时触发特定功能，比如打开商店、切换模式等。</p><h3 id="可破坏物与物品事件" tabindex="-1">可破坏物与物品事件 <a class="header-anchor" href="#可破坏物与物品事件" aria-label="Permalink to “可破坏物与物品事件”">​</a></h3><ol><li><strong>添加&quot;单位获得物品&quot;事件</strong> — 在触发器编辑器中，点击事件旁边的绿色&quot;新建&quot;按钮[^1]，在弹出的列表中找到&quot;单位 - A unit Acquires an item&quot;（单位获得物品）并点击选中。这个事件会在任何单位（玩家单位或中立敌对单位）获得物品时触发。</li><li><strong>添加&quot;单位失去物品&quot;事件</strong> — 同样方式新建事件，选择&quot;A unit Loses an item&quot;（单位失去物品）。常用于检测玩家是否丢弃了某个关键道具。</li><li><strong>使用物品条件过滤</strong> — 在触发器的&quot;条件&quot;区域，添加&quot;Unit - Unit of type&quot;条件，并指定你想要的物品类型（如&quot;生命药水&quot;）。这样只有获得特定物品时才会执行后面的操作[^2]。</li></ol><blockquote><p><strong>💡 新手提示</strong>：物品事件的&quot;单位&quot;指的是持有物品的英雄或士兵。地图上的物品（如木箱中的装备）被拾取后，才会触发&quot;获得物品&quot;事件。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手容易混淆&quot;获得&quot;和&quot;拾取&quot;——&quot;拾取&quot;事件只对有背包栏位的单位有效，而&quot;获得&quot;包括系统自动给予物品的情况。</p></blockquote><h3 id="对话框与变量事件" tabindex="-1">对话框与变量事件 <a class="header-anchor" href="#对话框与变量事件" aria-label="Permalink to “对话框与变量事件”">​</a></h3><ol><li><strong>创建对话框</strong> — 在触发器中新建动作，选择&quot;Dialog - Clear&quot;或&quot;Dialog - Create from button&quot;。对话框是一个隐藏的界面元素，不会自动显示，需要用动作手动显示给玩家[^3]。</li><li><strong>添加对话框按钮</strong> — 新建动作&quot;Dialog - Create a button for Dialog&quot;，设置按钮文字（如&quot;开始游戏&quot;、&quot;退出&quot;）。每个按钮都可以分配一个&quot;Clicked Button&quot;事件。</li><li><strong>绑定对话框点击事件</strong> — 新建事件，选择&quot;Dialog - A dialog button is clicked&quot;。这是对话框系统的核心事件——当玩家点击任意对话框按钮时触发，触发器会自动记录被点击的是哪个按钮。</li><li><strong>使用变量存储对话框</strong> — 把对话框和按钮保存到变量中，这样可以在多个触发器里重复使用同一个对话框[^2]。</li></ol><blockquote><p><strong>💡 新手提示</strong>：对话框事件需要先&quot;显示对话框&quot;给玩家看，否则玩家无法点击。常用动作是&quot;Dialog - Show all dialogs for Player&quot;。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：忘记把对话框保存到变量中！如果你在触发器A创建了对话框但在触发器B才引用它，必须用变量存储，否则触发器B找不到这个对话框。</p></blockquote><h3 id="小结-5" tabindex="-1">小结 <a class="header-anchor" href="#小结-5" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该已经掌握了物品事件的添加与条件过滤，以及对话框的创建、按钮配置和点击事件。这些事件组合起来，可以实现完整的物品奖励系统和玩家交互菜单——这是制作RPG地图不可或缺的两种功能。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://www.hiveworkshop.com/threads/basics-of-triggers.32113/" target="_blank" rel="noreferrer">Basics of Triggers - HIVE</a> — accessed 2026-05-07 [^2]: <a href="https://world-editor-tutorials.thehelper.net/cat_usersubmit.php?view=19780" target="_blank" rel="noreferrer">Triggers - Basic Guide - Warcraft III World Editor</a> — accessed 2026-05-07 [^3]: <a href="https://thelazzoro.github.io/BetterTriggersGuide" target="_blank" rel="noreferrer">Better Triggers – Nextra</a> — accessed 2026-05-07</p>',94)])])}const p=o(e,[["render",i]]);export{d as __pageData,p as default};
